func TestEnumLlmAdapter(t *testing.T) {
	t.Run("NewFromString_anthropic", func(t *testing.T) {
		t.Parallel()
		val, err := NewLlmAdapterFromString("anthropic")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LlmAdapter("anthropic"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_openai", func(t *testing.T) {
		t.Parallel()
		val, err := NewLlmAdapterFromString("openai")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LlmAdapter("openai"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_azure", func(t *testing.T) {
		t.Parallel()
		val, err := NewLlmAdapterFromString("azure")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LlmAdapter("azure"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_bedrock", func(t *testing.T) {
		t.Parallel()
		val, err := NewLlmAdapterFromString("bedrock")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LlmAdapter("bedrock"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_google_vertex_ai", func(t *testing.T) {
		t.Parallel()
		val, err := NewLlmAdapterFromString("google-vertex-ai")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LlmAdapter("google-vertex-ai"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_google_ai_studio", func(t *testing.T) {
		t.Parallel()
		val, err := NewLlmAdapterFromString("google-ai-studio")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, LlmAdapter("google-ai-studio"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewLlmAdapterFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewLlmAdapterFromString("anthropic")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

func TestExtraPropertiesDeleteLlmConnectionResponse(t *testing.T) {
	t.Run("GetExtraProperties", func(t *testing.T) {
		t.Parallel()
		obj := &DeleteLlmConnectionResponse{}
		// Should not panic when calling GetExtraProperties()
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("GetExtraProperties() panicked: %v", r)
			}
		}()
		extraProps := obj.GetExtraProperties()
		// Result can be nil or an empty/non-empty map
		_ = extraProps
	})

	t.Run("GetExtraProperties_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *DeleteLlmConnectionResponse
		extraProps := obj.GetExtraProperties()
		assert.Nil(t, extraProps, "nil receiver should return nil without panicking")
	})
}

